codeExample:
List<String> lista = new ArrayList<>();
lista.add("a");
lista.add("a"); // permite duplicata
System.out.println(lista.size()); // 2

Set<String> conjunto = new HashSet<>();
conjunto.add("a");
conjunto.add("a"); // ignorado — já existe
System.out.println(conjunto.size()); // 1

Map<String, Integer> idadePorNome = new HashMap<>();
idadePorNome.put("Ana", 30);
idadePorNome.put("Ana", 31); // sobrescreve o valor da chave existente
System.out.println(idadePorNome.get("Ana")); // 31
System.out.println(idadePorNome.size()); // 1 — chave é única

codeExampleBad:
public class Ponto {
    int x, y;
    Ponto(int x, int y) { this.x = x; this.y = y; }
    // faltou sobrescrever equals() e hashCode()!
}

Set<Ponto> pontos = new HashSet<>();
pontos.add(new Ponto(1, 1));
pontos.add(new Ponto(1, 1)); // "logicamente" igual ao anterior...

System.out.println(pontos.size());
// imprime 2, não 1! Sem equals()/hashCode() customizados, HashSet usa
// identidade de objeto (referência) — são dois objetos distintos na heap,
// mesmo com x e y iguais.
